import React from 'react';
import { Card, Stack, Heading, Text, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard - A visually rich component for displaying current weather and a 5-day forecast.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = [],
}: Props) {
  const displayUnit = unit ?? 'C';

  return (
    <Card
      shadow="md"
      radius="xl"
      padding="var(--ggui-spacing-6, 24px)"
      style={{
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        transition: 'transform 200ms ease',
        maxWidth: '450px',
      }}
    >
      <Stack direction="vertical" gap={20}>
        {/* Header Section */}
        <Stack direction="vertical" gap={4}>
          <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Heading>
          <Text
            variant="bodyLarge"
            weight="medium"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {condition}
          </Text>
        </Stack>

        {/* Main Temperature Section */}
        <Stack
          direction="horizontal"
          align="center"
          gap={8}
        >
          <Text
            size="4xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {temperature}°
          </Text>
          <Text
            size="xl"
            weight="medium"
            color="var(--ggui-color-neutral-500, #6b7280)"
            style={{ paddingTop: 'var(--ggui-spacing-2, 8px)' }}
          >
            {displayUnit}
          </Text>
        </Stack>

        {/* Details Section */}
        <Stack direction="horizontal" gap={24} justify="start">
          {/* Group A: Humidity */}
          <Stack direction="vertical" gap={2}>
            <Text
              variant="bodySmall"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
            <Text
              variant="bodySmall"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {humidity}%
            </Text>
          </Stack>

          {/* Group B: Wind Speed */}
          <Stack direction="vertical" gap={2}>
            <Text
              variant="bodySmall"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind
            </Text>
            <Text
              variant="bodySmall"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        {/* Forecast Section */}
        <Divider margin="var(--ggui-spacing-4, 16px)" color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        <Stack direction="horizontal" justify="between" gap={12}>
          {forecast?.map((item, index) => (
            <Box
              key={`${item.day}-${index}`}
              padding={8}
              borderRadius={12}
              style={{
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                flex: 1,
                minWidth: '60px',
                transition: 'background-color 200ms ease',
              }}
            >
              <Stack direction="vertical" gap={8} align="center">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {item.day}
                </Text>

                <Text
                  size="lg"
                >
                  {item.icon}
                </Text>

                <Stack direction="horizontal" gap={4} justify="center">
                  <Text
                    variant="bodySmall"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {item.high}°
                  </Text>
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {item.low}°
                  </Text>
                </Stack>
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}
